SELECT * FROM site_non_rebate_config
WHERE site_code = #{vo.siteCode}

    AND venue_type = #{vo.venueType}



    AND venue_code = #{vo.venueCode}



    AND updater = #{vo.updater}



    and JSON_CONTAINS(game_info, JSON_OBJECT('gameName', #{vo.gameName}), '$')


order by updated_time desc
